import json

# var_call_nvAzWHrQkjfAMe8uwKiAgYVV is a string path to the full business collection result JSON
business_file_path = var_call_nvAzWHrQkjfAMe8uwKiAgYVV
with open(business_file_path, 'r', encoding='utf-8') as f:
    businesses = json.load(f)

# var_call_j2WazwfwzHKh9nHR0g4Qxwq6 is the list of dicts with business_ref and avg_rating
avg_list = var_call_j2WazwfwzHKh9nHR0g4Qxwq6
# build mapping from business_ref to float avg rating
avg_map = {}
for r in avg_list:
    br = r.get('business_ref')
    avg = r.get('avg_rating')
    try:
        avg_map[br] = float(avg)
    except:
        continue

# accumulate stats per category
from collections import defaultdict
stats = {}

for b in businesses:
    b_id = b.get('business_id')
    if not b_id:
        continue
    attrs = b.get('attributes')
    accepts = False
    if isinstance(attrs, dict):
        val = attrs.get('BusinessAcceptsCreditCards')
        if isinstance(val, str):
            if 'True' in val or 'true' in val:
                accepts = True
        elif val is True:
            accepts = True
    # skip if not accepting credit cards
    if not accepts:
        continue
    # categories may be a string of comma-separated categories
    cats = b.get('categories')
    if not cats:
        continue
    if isinstance(cats, list):
        parts = [c.strip() for c in cats if c and isinstance(c, str)]
    else:
        # string
        parts = [c.strip() for c in cats.split(',') if c.strip()]
    if not parts:
        continue
    # get avg rating for this business if available
    business_ref = b_id.replace('businessid_', 'businessref_')
    rating = avg_map.get(business_ref)
    for cat in parts:
        if cat not in stats:
            stats[cat] = {'count': 0, 'rating_sum': 0.0, 'rating_count': 0}
        stats[cat]['count'] += 1
        if rating is not None:
            stats[cat]['rating_sum'] += rating
            stats[cat]['rating_count'] += 1

# find category with largest count
if not stats:
    result = {'category': None, 'count': 0, 'average_rating': None}
else:
    max_cat = max(stats.items(), key=lambda x: x[1]['count'])[0]
    rec = stats[max_cat]
    if rec['rating_count'] > 0:
        avg_rating = rec['rating_sum'] / rec['rating_count']
    else:
        avg_rating = None
    # round average rating to 3 decimals if not None
    if avg_rating is not None:
        avg_rating = round(avg_rating, 3)
    result = {'category': max_cat, 'count': rec['count'], 'average_rating': avg_rating}

import json
print("__RESULT__:")
print(json.dumps(result))

